package plugin

import (
	"context"
	"encoding/binary"
	"encoding/hex"
	"errors"
	"fmt"
	"net"
	"strings"
	"time"

	"github.com/evcc-io/evcc/util"
)

// AA55UDP implements the GoodWe WiFi AA55-over-UDP wire protocol as a generic
// evcc source plugin.
//
// The inverter speaks a simple request/response protocol over UDP port 8899:
//
//	Request:  [6-byte Modbus PDU body] [Modbus CRC-16, little-endian]
//	Response: AA 55 [src] 03 [byteCount] [payload…] [CRC]
//
// src varies by inverter family (0x7F for DT/DNS, 0xF7 for ET/EH/BT/BH);
// only the AA 55 magic bytes and function code 0x03 are validated.
//
// Each instance reads exactly one value from one register (or register pair
// for 32-bit values), matching how Modbus source plugins work.  The PDU is
// constructed from register and count; the decoded value is always at offset 0
// of the response payload.
type AA55UDP struct {
	log    *util.Logger
	conn   *net.UDPConn
	pdu    []byte // 6-byte PDU body, no CRC
	decode string // int32be | uint32be | int16be | uint16be
	scale  float64
}

func init() {
	registry.AddCtx("aa55udp", NewAA55UDPFromConfig)
}

// NewAA55UDPFromConfig creates an AA55UDP plugin from a source block:
//
//	source:   aa55udp
//	host:     192.168.1.26   # inverter IP; port 8899 is always used
//	register: 30127          # Modbus register address (0-based, uint16)
//	count:    2              # number of registers to read (1=U16, 2=S32/U32)
//	decode:   int32be        # int32be | uint32be | int16be | uint16be
//	scale:    1.0            # optional multiplier (default 1.0)
func NewAA55UDPFromConfig(_ context.Context, other map[string]interface{}) (Plugin, error) {
	cc := struct {
		Host     string  `mapstructure:"host"`
		Register uint16  `mapstructure:"register"`
		Count    uint16  `mapstructure:"count"`
		Decode   string  `mapstructure:"decode"`
		Scale    float64 `mapstructure:"scale"`
	}{
		Count: 2,
		Scale: 1.0,
	}
	if err := util.DecodeOther(other, &cc); err != nil {
		return nil, err
	}

	if cc.Count == 0 {
		return nil, errors.New("aa55udp: count must be ≥ 1")
	}

	switch cc.Decode {
	case "int32be", "uint32be", "int16be", "uint16be":
	default:
		return nil, fmt.Errorf("aa55udp: unsupported decode %q (want int32be|uint32be|int16be|uint16be)", cc.Decode)
	}

	pdu := buildPDU(cc.Register, cc.Count)

	addr, err := net.ResolveUDPAddr("udp4", net.JoinHostPort(cc.Host, "8899"))
	if err != nil {
		return nil, fmt.Errorf("aa55udp: resolve %s: %w", cc.Host, err)
	}

	conn, err := net.DialUDP("udp4", nil, addr)
	if err != nil {
		return nil, fmt.Errorf("aa55udp: dial %s: %w", cc.Host, err)
	}

	return &AA55UDP{
		log:    util.NewLogger("aa55udp"),
		conn:   conn,
		pdu:    pdu,
		decode: cc.Decode,
		scale:  cc.Scale,
	}, nil
}

// FloatGetter implements the evcc Plugin interface.
func (p *AA55UDP) FloatGetter() (func() (float64, error), error) {
	return p.query, nil
}

// query sends the PDU and returns the decoded, scaled value at offset 0 of the
// response payload.
func (p *AA55UDP) query() (float64, error) {
	packet := append(p.pdu, modbusCRC16(p.pdu)...)

	if _, err := p.conn.Write(packet); err != nil {
		return 0, fmt.Errorf("aa55udp write: %w", err)
	}

	if err := p.conn.SetReadDeadline(time.Now().Add(4 * time.Second)); err != nil {
		return 0, fmt.Errorf("aa55udp deadline: %w", err)
	}

	buf := make([]byte, 512)
	n, err := p.conn.Read(buf)
	if err != nil {
		return 0, fmt.Errorf("aa55udp read: %w", err)
	}

	payload, err := stripAA55Header(buf[:n])
	if err != nil {
		return 0, fmt.Errorf("aa55udp: %w", err)
	}

	v, err := decodeAt(payload, 0, p.decode)
	if err != nil {
		return 0, fmt.Errorf("aa55udp: %w", err)
	}

	return v * p.scale, nil
}

// aa55InverterAddr is the target address byte used in all AA55 request PDUs.
// The GoodWe WiFi module always uses 0x7F as the inverter target address,
// regardless of inverter family. The family only affects the source byte in
// responses (0x7F for DT/DNS, 0xF7 for ET/EH/BT/BH).
const aa55InverterAddr = 0x7F

// aa55ReadFunc is the Modbus function code for READ HOLDING REGISTERS.
const aa55ReadFunc = 0x03

// buildPDU constructs the 6-byte Modbus PDU body for a READ HOLDING REGISTERS
// request targeting the GoodWe WiFi module.
func buildPDU(register, count uint16) []byte {
	return []byte{
		aa55InverterAddr, aa55ReadFunc,
		byte(register >> 8), byte(register),
		byte(count >> 8), byte(count),
	}
}

// parsePDUHex decodes a hex string (spaces allowed) into exactly 6 bytes.
// Kept for use in tests.
func parsePDUHex(s string) ([]byte, error) {
	clean := strings.ReplaceAll(s, " ", "")
	b, err := hex.DecodeString(clean)
	if err != nil {
		return nil, fmt.Errorf("aa55udp: invalid pdu %q: %w", s, err)
	}
	if len(b) != 6 {
		return nil, fmt.Errorf("aa55udp: pdu must be 6 bytes, got %d", len(b))
	}
	return b, nil
}

// stripAA55Header validates the AA55 response frame and returns the bare
// payload (without the 5-byte header and trailing 2-byte CRC).
// buf[2] is the inverter source address and varies by family — only the
// AA 55 magic bytes and function code 0x03 are validated.
func stripAA55Header(buf []byte) ([]byte, error) {
	if len(buf) < 6 || buf[0] != 0xAA || buf[1] != 0x55 || buf[3] != 0x03 {
		return nil, errors.New("invalid response header")
	}
	byteCount := int(buf[4])
	if len(buf) < 5+byteCount+2 {
		return nil, errors.New("short response")
	}
	return buf[5 : 5+byteCount], nil
}

// decodeAt extracts an integer at the given byte offset of payload and
// interprets it according to decode.
func decodeAt(payload []byte, offset int, decode string) (float64, error) {
	switch decode {
	case "int32be":
		if len(payload) < offset+4 {
			return 0, fmt.Errorf("payload too short for int32be at offset %d (len=%d)", offset, len(payload))
		}
		return float64(int32(binary.BigEndian.Uint32(payload[offset:]))), nil
	case "uint32be":
		if len(payload) < offset+4 {
			return 0, fmt.Errorf("payload too short for uint32be at offset %d (len=%d)", offset, len(payload))
		}
		return float64(binary.BigEndian.Uint32(payload[offset:])), nil
	case "int16be":
		if len(payload) < offset+2 {
			return 0, fmt.Errorf("payload too short for int16be at offset %d (len=%d)", offset, len(payload))
		}
		return float64(int16(binary.BigEndian.Uint16(payload[offset:]))), nil
	case "uint16be":
		if len(payload) < offset+2 {
			return 0, fmt.Errorf("payload too short for uint16be at offset %d (len=%d)", offset, len(payload))
		}
		return float64(binary.BigEndian.Uint16(payload[offset:])), nil
	}
	return 0, fmt.Errorf("unknown decode type: %s", decode)
}

// modbusCRC16 computes the Modbus CRC-16 (little-endian byte order).
func modbusCRC16(data []byte) []byte {
	crc := uint16(0xFFFF)
	for _, b := range data {
		crc ^= uint16(b)
		for i := 0; i < 8; i++ {
			if crc&0x0001 != 0 {
				crc = (crc >> 1) ^ 0xA001
			} else {
				crc >>= 1
			}
		}
	}
	return []byte{byte(crc & 0xFF), byte(crc >> 8)}
}

	// 32 bit
	case "int32":
		return asFloat64(encoding.Int32), nil
	case "int32nan":
		return decodeNaN32(asFloat64(encoding.Int32), 1<<31, 1<<31-1), nil
	case "int32s":
		return asFloat64(encoding.Int32LswFirst), nil
	case "uint32":
		return asFloat64(encoding.Uint32), nil
	case "uint32s":
		return asFloat64(encoding.Uint32LswFirst), nil
	case "uint32nan":
		return decodeNaN32(asFloat64(encoding.Uint32), 1<<32-1), nil
	case "float32", "ieee754":
		return asFloat64(encoding.Float32), nil
	case "float32s", "ieee754s":
		return asFloat64(encoding.Float32LswFirst), nil
	case "float32nans":
		return decodeNaN32(asFloat64(encoding.Float32LswFirst), 0xffffff7f), nil

	// 64 bit
	case "int64":
		return asFloat64(encoding.Int64), nil
	case "uint64":
		return asFloat64(encoding.Uint64), nil
	case "uint64nan":
		return decodeNaN64(asFloat64(encoding.Uint64), 1<<64-1), nil
	case "float64":
		return encoding.Float64, nil

	default:
		return nil, fmt.Errorf("invalid register decoding: %s", r.encoding())
	}
}

func (r Register) encodeToBytes(fun func(float64) uint64) (func(float64) ([]byte, error), error) {
	length, err := r.Length()
	if err != nil {
		return nil, err
	}

	// swapped
	if strings.HasSuffix(strings.ToLower(r.encoding()), "s") {
		if length != 2 {
			return nil, fmt.Errorf("invalid swapped encoding register length: %d", length)
		}

		inner := fun
		fun = func(f float64) uint64 {
			v := inner(f)
			return v&0xFFFF<<16 | v&0xFFFF0000>>16
		}
	}

	return func(f float64) ([]byte, error) {
		v := fun(f)
		b := make([]byte, 2*length)

		switch length {
		case 1:
			binary.BigEndian.PutUint16(b[:], uint16(v))
		case 2:
			binary.BigEndian.PutUint32(b[:], uint32(v))
		case 4:
			binary.BigEndian.PutUint64(b[:], v)
		default:
			return nil, fmt.Errorf("invalid register length: %d", length)
		}

		return b, nil
	}, nil
}

func (r Register) EncodeFunc() (func(float64) ([]byte, error), error) {
	enc := strings.ToLower(r.encoding())

	switch {
	case strings.HasPrefix(enc, "bool"):
		fallthrough

	case strings.HasPrefix(enc, "int"):
		return r.encodeToBytes(func(v float64) uint64 {
			return uint64(int64(v))
		})

	case strings.HasPrefix(enc, "uint"):
		return r.encodeToBytes(func(v float64) uint64 {
			return uint64(v)
		})

	case strings.HasPrefix(enc, "float") || strings.HasPrefix(enc, "ieee754"):
		length, err := r.Length()
		if err != nil {
			return nil, err
		}

		switch length {
		case 2:
			return r.encodeToBytes(func(v float64) uint64 {
				return uint64(math.Float32bits(float32(v)))
			})

		case 4:
			return r.encodeToBytes(func(v float64) uint64 {
				return math.Float64bits(v)
			})

		default:
			return nil, fmt.Errorf("invalid register length: %d", length)
		}

	default:
		return nil, fmt.Errorf("invalid register encoding: %s", r.encoding())
	}
}

type RegisterOperation struct {
	FuncCode uint8
	Addr     uint16

package plugin

import (
	"encoding/binary"
	"encoding/hex"
	"net"
	"testing"

	"github.com/evcc-io/evcc/util"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// ---------------------------------------------------------------------------
// Real captured frames (marcelblijleven/goodwe tests/sample/ + discussion #27411)
// ---------------------------------------------------------------------------
//
// All frames are verbatim UDP datagrams received from real inverters.
// In the per-register protocol each PDU fetches exactly one value; the
// response payload starts at offset 0.
//
// Register map summary:
//
//  Family  Reading   Register  Count  Decode    Expected (captures below)
//  DT      power     0x75AF    2      int32be   GW3000-DNS-30=1972W  GW17K-DT=12470W
//  DT      energy    0x75C1    2      uint32be  GW17K-DT=29984.4kWh  GW6000-DT=13350.2kWh
//  ES      pv        0x7506    2      int32be
//  ES      grid      0x750C    2      int32be
//  ES      battery   0x7512    2      int32be
//  ES      soc       0x750E    1      uint16be
//  ET      pv        0x8941    2      int32be   GW10K-ET=831W
//  ET      grid      0x8943    2      int32be   GW10K-ET=-3W  GW25K-ET=1511W  GW29K9-ET=-5403W
//  ET      battery   0x896E    2      int32be   GW10K-ET=-2512W (charging)
//  ET      energy    0x8977    2      uint32be  GW10K-ET=6085.3kWh  GW25K-ET=160.3kWh
//  ET      soc       0x908F    1      uint16be  GW10K-ET=68%  GW25K-ET=100%
//
// Note: these captures are full block-read responses used to verify the
// per-register values at offset 0 of what the inverter would return for
// a targeted single-register read. The payload bytes at the register's
// offset within the block are identical to what a per-register read returns.

const (
	// DT family (source byte 0x7F, block PDU READ 73 @ 0x7594)
	capGW3000DNS30 = ``
	capGW17kDT     = ``
	capGW20kAUDT   = ``
	capGW6000DT    = ``

	// ET family (source byte 0xF7, block PDU READ 125 @ 0x891C)
	capGW10kET  = ``
	capGW25kET  = ``
	capGW29k9ET = ``

	// ET battery info (source byte 0xF7, block PDU READ 24 @ 0x9088)
	capGW10kETBattery = `aa55f7033000ff01000001015e001900190000004400630005000001010000000000000000000000000000000000000000000000006447`
	capGW25kETBattery = `aa55f7033000ff0137000100e600000028000000640064000400000105000000000316000000000000000000000000000000000000dc7a`
)

// ---------------------------------------------------------------------------
// buildPDU tests
// ---------------------------------------------------------------------------

func TestBuildPDU_DTpower(t *testing.T) {
	// DT power: register 0x75AF, count 2 → READ 2 @ 0x75AF
	got := buildPDU(0x75AF, 2)
	assert.Equal(t, []byte{0x7f, 0x03, 0x75, 0xaf, 0x00, 0x02}, got)
