func TestDecodeAt_TooShort(t *testing.T) {
	_, err := decodeAt([]byte{0x00}, 0, "int32be")
	require.Error(t, err)
}

func TestDecodeAt_Float32(t *testing.T) {
	payload := make([]byte, 4)
	f := float32(1234.5)
	binary.BigEndian.PutUint32(payload, math.Float32bits(f))
	v, err := decodeAt(payload, 0, "float32")
	require.NoError(t, err)
	assert.InDelta(t, 1234.5, v, 0.001)
}

